def recommend_stripe_config(file_type, file_size_gb=1.0,
                            num_osts=16):
    if file_type == "checkpoint":
        sc = min(num_osts, max(1, int(file_size_gb * 4)))
        return {"stripe_count": sc, "stripe_size": "4M"}
    elif file_type == "dataset_shards":
        return {"stripe_count": 4, "stripe_size": "4M"}
    elif file_type == "small_files":
        return {"stripe_count": 1, "stripe_size": "1M"}
    elif file_type == "model_weights":
        return {"stripe_count": min(num_osts, 8), "stripe_size": "4M"}
    else:
        return {"stripe_count": 1, "stripe_size": "1M"}
