class ModelRegistry:
    VALID_STAGES = {"None", "Staging", "Production", "Archived"}

    def __init__(self):
        self.models = {}

    def register(self, name, version, metadata=None):
        self.models[(name, version)] = {
            "name": name,
            "version": version,
            "stage": "None",
            "metadata": metadata or {},
        }

    def promote(self, name, version, stage):
        if stage not in self.VALID_STAGES:
            return False
        key = (name, version)
        if key not in self.models:
            return False
        self.models[key]["stage"] = stage
        return True

    def get_production_model(self, name):
        prod = None
        for (n, v), info in self.models.items():
            if n == name and info["stage"] == "Production":
                if prod is None or v > prod["version"]:
                    prod = info
        return prod
```

