def split_traffic(total_requests, model_weights):
    shares = {}
    for model, weight in model_weights.items():
        exact = total_requests * weight
        shares[model] = {
            "floor": int(exact),
            "remainder": exact - int(exact),
        }

    allocated = sum(s["floor"] for s in shares.values())
    leftover = total_requests - allocated

    # Sort by remainder descending to allocate leftover
    sorted_models = sorted(
        shares.keys(),
        key=lambda m: shares[m]["remainder"],
        reverse=True,
    )

    result = {m: shares[m]["floor"] for m in shares}
    for i in range(leftover):
        result[sorted_models[i]] += 1
    return result
```
